+
+        try std.testing.expect(result.columns[0].data == .float64);
+        const stddev = result.columns[0].data.float64[0];
+        try std.testing.expectApproxEqAbs(@as(f64, 1.5811388300841898), stddev, 0.0001);
+    }
+
